type RetryOptions = {
  retries?: number;
  initialDelayMs?: number;
  maxDelayMs?: number;
  factor?: number;
  shouldRetry?: (error: unknown, attempt: number) => boolean;
};

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

export async function retryNetworkCall<T>(
  call: () => Promise<T>,
  {
    retries = 3,
    initialDelayMs = 250,
    maxDelayMs = 5_000,
    factor = 2,
    shouldRetry = () => true,
  }: RetryOptions = {}
): Promise<T> {
  if (retries < 0) throw new Error("retries must be >= 0");
  if (initialDelayMs < 0) throw new Error("initialDelayMs must be >= 0");
  if (maxDelayMs < initialDelayMs) throw new Error("maxDelayMs must be >= initialDelayMs");
  if (factor < 1) throw new Error("factor must be >= 1");

  let lastError: unknown;

  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      return await call();
    } catch (error) {
      lastError = error;

      const hasAttemptLeft = attempt < retries;
      if (!hasAttemptLeft || !shouldRetry(error, attempt)) {
        throw error;
      }

      const delay = Math.min(initialDelayMs * factor ** attempt, maxDelayMs);
      await sleep(delay);
    }
  }

  throw lastError;
}
```

