Here is a correct, secure TypeScript retry helper:

```ts
type RetryOptions = {
  retries?: number;
  baseDelayMs?: number;
  maxDelayMs?: number;
  timeoutMs?: number;
  retryOn?: (error: unknown, attempt: number) => boolean;
};

const sleep = (ms: number, signal?: AbortSignal) =>
  new Promise<void>((resolve, reject) => {
    const timer = setTimeout(resolve, ms);

    signal?.addEventListener(
      "abort",
      () => {
        clearTimeout(timer);
        reject(signal.reason ?? new Error("Operation aborted"));
      },
      { once: true }
    );
  });

export async function retryNetworkCall<T>(
  fn: (signal: AbortSignal) => Promise<T>,
  options: RetryOptions = {}
): Promise<T> {
  const {
    retries = 3,
    baseDelayMs = 250,
    maxDelayMs = 2_000,
    timeoutMs = 10_000,
    retryOn = () => true,
  } = options;

  let lastError: unknown;

  for (let attempt = 0; attempt <= retries; attempt++) {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(new Error("Request timed out")), timeoutMs);

    try {
      return await fn(controller.signal);
    } catch (error) {
      lastError = error;

      if (attempt === retries || !retryOn(error, attempt)) {
        throw error;
      }

      const exponentialDelay = Math.min(maxDelayMs, baseDelayMs * 2 ** attempt);
      const jitter = Math.floor(Math.random() * exponentialDelay * 0.25);

      await sleep(exponentialDelay + jitter);
    } finally {
      clearTimeout(timeout);
    }
  }

  throw lastError;
}
```

Example use:

```ts
const data = await retryNetworkCall(
  signal =>
    fetch("https://api.example.com/data", { signal }).then(response => {
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return response.json();
    }),
  {
    retries: 4,
    timeoutMs: 5_000,
    retryOn: error => {
      return error instanceof Error && !error.message.startsWith("HTTP 4");
    },
  }
);
```

